import{_ as e,o as l,c as i,a2 as r}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Настройки загрузки","description":"","frontmatter":{},"headers":[],"relativePath":"ru-RU/upload/index.md","filePath":"ru-RU/upload/index.md","lastUpdated":1781962217000}'),o={name:"ru-RU/upload/index.md"};function t(d,a,n,h,s,u){return l(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="настроики-загрузки" tabindex="-1">Настройки загрузки <a class="header-anchor" href="#настроики-загрузки" aria-label="Permalink to &quot;Настройки загрузки&quot;">​</a></h1><p>В этом разделе каналы идут в том же порядке, что и на странице системных настроек, поэтому можно сразу перейти к нужному провайдеру хранилища.</p><h2 id="как-устроен-раздел" tabindex="-1">Как устроен раздел <a class="header-anchor" href="#как-устроен-раздел" aria-label="Permalink to &quot;Как устроен раздел&quot;">​</a></h2><ul><li>Для каждого провайдера есть отдельная страница. Так 13 каналов загрузки проще настраивать без путаницы.</li><li>Скриншоты хранятся в <code>../../image/upload/provider-name/</code> и подключаются локально на соответствующих страницах.</li><li>Русская документация локализована по смыслу пользовательской инструкции; названия полей по возможности оставлены близкими к интерфейсу продукта.</li></ul><h2 id="список-каналов" tabindex="-1">Список каналов <a class="header-anchor" href="#список-каналов" aria-label="Permalink to &quot;Список каналов&quot;">​</a></h2><ul><li><a href="./telegram">Telegram</a></li><li><a href="./cloudflare-r2">Cloudflare R2</a></li><li><a href="./s3">S3</a></li><li><a href="./webdav">WebDAV</a></li><li><a href="./discord">Discord</a></li><li><a href="./huggingface">Hugging Face</a></li><li><a href="./github-releases">GitHub Releases</a></li><li><a href="./gitlab-packages">GitLab Packages</a></li><li><a href="./onedrive">OneDrive</a></li><li><a href="./google-drive">Google Drive</a></li><li><a href="./dropbox">Dropbox</a></li><li><a href="./yandex">Yandex</a></li><li><a href="./pcloud">pCloud</a></li></ul><h2 id="что-описано-в-этом-разделе" tabindex="-1">Что описано в этом разделе <a class="header-anchor" href="#что-описано-в-этом-разделе" aria-label="Permalink to &quot;Что описано в этом разделе&quot;">​</a></h2><ul><li>Как добавить каждый канал загрузки.</li><li>Какие ключи, идентификаторы или учетные данные нужны перед добавлением канала.</li><li>Как проверить, что канал готов принимать файлы.</li></ul><p>Подробности по устранению неполадок, стратегиям квот и практикам использования вынесены в отдельные места там, где это нужно.</p>',9)])])}const p=e(o,[["render",t]]);export{f as __pageData,p as default};
